impl.spec_text:
trait T { spec fn f() -> bool; }
struct S<A> { a: A }
impl T for S<u8> { spec fn f() -> bool { true } }
impl T for S<bool> { spec fn f() -> bool { false } }
proof fn test() {
    assert(S::<u8>::f() == S::<bool>::f()); // FAILS
}

